1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; cursed?: boolean; enchantment?: number };
14	type Damage = { itemType: string; amount: number };
15	type Incident = { cause: string; damages: Damage[] };
16	type Step = { op: string; items?: Item[]; policy?: number; incident?: Incident };
17	type Customer = { yearsWithMHPCO: number };
18	type Input = { customer: Customer; steps: Step[] };
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const DEDUCTIBLE = 100;
30	
31	type Policy = { items: Item[]; remainingCap: number };
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const BLOCK_BASE_PREMIUM = 60;
35	const BLOCK_SIZE = 3;
36	
37	const withFirstInsurance = (base: number): number =>
38	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
39	
40	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
43	
44	const groupByType = (items: Item[]): Map<string, Item[]> => {
45	  const groups = new Map<string, Item[]>();
46	  for (const item of items) {
47	    const group = groups.get(item.type) ?? [];
48	    group.push(item);
49	    groups.set(item.type, group);
50	  }
51	  return groups;
52	};
53	
54	const componentGroupBasePremium = (group: Item[]): number =>
55	  group.length === BLOCK_SIZE
56	    ? BLOCK_BASE_PREMIUM
57	    : group.reduce((sum, item) => sum + itemBasePremium(item), 0);
58	
59	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
60	
61	const policyBasePremium = (items: Item[]): number => {
62	  const components = items.filter(isComponent);
63	  const nonComponents = items.filter((item) => !isComponent(item));
64	  const nonComponentBases = nonComponents.map(itemBasePremium);
65	  const componentGroupBases = [...groupByType(components).values()].map(
66	    componentGroupBasePremium,
67	  );
68	  return sum(nonComponentBases) + sum(componentGroupBases);
69	};
70	
71	const itemsSubtotal = (items: Item[]): number => {
72	  const components = items.filter(isComponent);
73	  const nonComponents = items.filter((item) => !isComponent(item));
74	
75	  const nonComponentPremiums = nonComponents.map((item) => {
76	    const base = itemBasePremium(item);
77	    const curseSurcharge = item.cursed ? base * 0.5 : 0;
78	    const highEnchSurcharge = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
79	    return base + curseSurcharge + highEnchSurcharge + base * FIRST_INSURANCE_SURCHARGE_RATE;
80	  });
81	  const componentGroupPremiums = [...groupByType(components).values()].map(
82	    (group) => withFirstInsurance(componentGroupBasePremium(group)),
83	  );
84	
85	  return sum(nonComponentPremiums) + sum(componentGroupPremiums);
86	};
87	
88	const quotePremium = (step: Step, customer: Customer, quoteIndex: number): number => {
89	  const subtotal = itemsSubtotal(step.items);
90	  const policyBase = policyBasePremium(step.items);
91	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
92	  const followUpDiscount = quoteIndex >= 1 ? policyBase * 0.15 : 0;
93	  return Math.ceil(subtotal - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
94	};
95	
96	const insuranceSum = (items: Item[]): number =>
97	  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
98	
99	const processClaim = (step: Step, policies: Policy[]): { payout: number; remainingCap: number } => {
100	  const policy = policies[step.policy ?? 0];
101	  const damages = step.incident?.damages ?? [];
102	  const totalPayout = damages.reduce((sum, d) => {
103	    const item = policy.items.find((i) => i.type === d.itemType);
104	    const baseReimbursement = (item?.enchantment ?? 0) >= 8 ? d.amount * 0.5 : d.amount;
105	    return sum + (baseReimbursement - DEDUCTIBLE);
106	  }, 0);
107	  const computedPayout = Math.floor(totalPayout);
108	  const payout = Math.min(computedPayout, policy.remainingCap);
109	  policy.remainingCap -= payout;
110	  return { payout, remainingCap: policy.remainingCap };
111	};
112	
113	const validateQuoteItems = (items: Item[]): void => {
114	  for (const item of items) {
115	    if (!(item.type in BASE_PREMIUMS)) {
116	      throw new Error(`Unknown item type: ${item.type}`);
117	    }
118	  }
119	};
120	
121	const validateClaim = (step: Step, policies: Policy[]): void => {
122	  const policy = policies[step.policy ?? 0];
123	  const damages = step.incident?.damages ?? [];
124	  const policyTypeCounts = new Map<string, number>();
125	  for (const item of policy.items) {
126	    policyTypeCounts.set(item.type, (policyTypeCounts.get(item.type) ?? 0) + 1);
127	  }
128	  const damageTypeCounts = new Map<string, number>();
129	  for (const d of damages) {
130	    if (d.amount < 0) {
131	      throw new Error(`Negative damage amount: ${d.amount}`);
132	    }
133	    if (!policyTypeCounts.has(d.itemType)) {
134	      throw new Error(`Claim against item not in policy: ${d.itemType}`);
135	    }
136	    damageTypeCounts.set(d.itemType, (damageTypeCounts.get(d.itemType) ?? 0) + 1);
137	    if (damageTypeCounts.get(d.itemType)! > policyTypeCounts.get(d.itemType)!) {
138	      throw new Error(`More damages of type ${d.itemType} than insured items`);
139	    }
140	  }
141	};
142	
143	export const runScenario = (input: unknown): unknown => {
144	  const { customer, steps } = input as Input;
145	  let quoteIndex = 0;
146	  const policies: Policy[] = [];
147	  const results = steps.map((step) => {
148	    if (step.op === "quote") {
149	      const items = step.items ?? [];
150	      validateQuoteItems(items);
151	      const premium = quotePremium({ op: step.op, items }, customer, quoteIndex);
152	      quoteIndex++;
153	      policies.push({ items, remainingCap: 2 * insuranceSum(items) });
154	      return { premium };
155	    }
156	    validateClaim(step, policies);
157	    return processClaim(step, policies);
158	  });
159	  return { results };
160	};
