3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	};
10	
11	const main = async (): Promise<void> => {
12	  const input = await readStdin();
13	  const scenario = JSON.parse(input);
14	  try {
15	    const result = runScenario(scenario);
16	    process.stdout.write(JSON.stringify(result));
17	  } catch (error) {
18	    process.stderr.write(error instanceof Error ? error.message : String(error));
19	    process.exit(1);
20	  }
21	};
22	
23	main();
